# BEST PRACTICE: Adaptive Hierarchical Refinement with confidence thresholding
class CricketMatchPlanner:
    def decompose_innings_strategy(self, goal: str, confidence_threshold: float = 0.7):
        """Decompose innings strategy with adaptive granularity."""
        initial_tasks = self._generate_hypothesis_tasks(goal)
        decomposed = []

        for task in initial_tasks:
            confidence = self._estimate_task_confidence(task)

            if confidence > confidence_threshold:
                # High confidence: aggressive parallelization
                subtasks = self._decompose_breadth_first(task, branches=3)
            else:
                # Low confidence: sequential refinement with checkpoints
                subtasks = self._decompose_depth_first_with_checkpoints(task)

            decomposed.extend(subtasks)

        return self._merge_results(decomposed)

# ANTI-PATTERN: Fixed decomposition regardless of context
class NaiveCricketPlanner:
    def decompose_innings_strategy(self, goal: str):
        """Always uses depth-first, no adaptation."""
        tasks = self._generate_all_tasks(goal)  # Rigid, context-blind

        for task in tasks:
            # Executes sequentially even when parallelization is safe
            result = self._execute_blocking(task)
            # No confidence check = missed optimization opportunities

        return result

# KEY DIFFERENCE:
# Best Practice: confidence_threshold drives decomposition strategy (adaptive)
# Anti-Pattern: Same decomposition regardless of task characteristics (rigid)
# Impact: Best practice reduces latency by 40-60% on varied workloads

# Production-grade goal decomposition: Match Planning System
from dataclasses import dataclass
from typing import List, Dict
from enum import Enum

class MatchPhase(Enum):
    POWERPLAY = "powerplay"
    MIDDLE_OVERS = "middle_overs"
    DEATH_OVERS = "death_overs"

@dataclass
class MatchGoal:
    target_runs: int
    overs_available: int
    phase: MatchPhase
    constraints: Dict[str, int]  # e.g., "max_boundaries": 8

class MatchDecomposer:
    def decompose_goal(self, goal: MatchGoal) -> Dict[str, object]:
        """
        Production decomposition: Match goal → agent subtasks
        """
        runs_per_over = goal.target_runs / goal.overs_available

        subtasks = {
            "batting_agent": {
                "goal": f"score {goal.target_runs} runs",
                "strategy": self._batting_strategy(goal.phase, runs_per_over),
                "constraints": goal.constraints,
                "checkpoint_every_over": True
            },
            "bowling_agent": {
                "goal": "restrict opposition runs",
                "strategy": self._bowling_strategy(goal.phase),
                "retry_on_injury": {"max_attempts": 3, "backup_bowler": True}
            },
            "field_agent": {
                "goal": "optimize field placement",
                "depends_on": ["batting_agent", "bowling_agent"],
                "recalculate_every_over": True
            }
        }
        return subtasks

    def _batting_strategy(self, phase: MatchPhase, rpo: float) -> str:
        if phase == MatchPhase.POWERPLAY:
            return f"aggressive: aim for {rpo * 1.5:.1f} RPO"
        elif phase == MatchPhase.DEATH_OVERS:
            return f"accelerate: target {rpo * 1.3:.1f} RPO"
        return f"steady: maintain {rpo:.1f} RPO"

    def _bowling_strategy(self, phase: MatchPhase) -> str:
        strategies = {
            MatchPhase.POWERPLAY: "pace bowlers: yorkers & short balls",
            MatchPhase.MIDDLE_OVERS: "spinners: dot balls & pressure",
            MatchPhase.DEATH_OVERS: "death specialists: yorkers & variations"
        }
        return strategies[phase]

# Usage
goal = MatchGoal(
    target_runs=180,
    overs_available=20,
    phase=MatchPhase.POWERPLAY,
    constraints={"max_boundaries": 8, "wickets_lost": 0}
)

decomposer = MatchDecomposer()
subtasks = decomposer.decompose_goal(goal)
print(f"Decomposed goal into {len(subtasks)} agent subtasks")
